The Chart
Quarto has some troubles breaking down multiple js chucks so it is best to just create your charts in one block.

chart = {
  const width = 1000, height = 520;
  const margin = { top: 20, right: 30, bottom: 50, left: 60 };
  const innerWidth  = width  - margin.left - margin.right;
  const innerHeight = height - margin.top  - margin.bottom;

  const svg = d3.create("svg")
    .attr("width", width)
    .attr("height", height);

  const g = svg.append("g")
    .attr("transform", `translate(${margin.left},${margin.top})`);

  const x = d3.scaleBand()
    .domain(avg_age_by_class.map(d =&gt; "Class " + d.Class))
    .range([0, innerWidth])
    .padding(0.3);

  const y = d3.scaleLinear()
    .domain([0, 45])
    .range([innerHeight, 0]);

  g.append("g")
    .attr("stroke", "#e0e0e0")
    .attr("stroke-dasharray", "4,2")
    .selectAll("line")
    .data(y.ticks(5))
    .join("line")
      .attr("x1", 0).attr("x2", innerWidth)
      .attr("y1", d =&gt; y(d))
      .attr("y2", d =&gt; y(d));

  g.selectAll("rect")
    .data(avg_age_by_class)
    .join("rect")
    .attr("x",      d =&gt; x("Class " + d.Class))
    .attr("y",      d =&gt; y(d["Average Age"]))
    .attr("width",  x.bandwidth())
    .attr("height", d =&gt; innerHeight - y(d["Average Age"]))
    .attr("fill", "steelblue")
    .attr("rx", 4);

  g.selectAll("text.label")
    .data(avg_age_by_class)
    .join("text")
    .attr("x", d =&gt; x("Class " + d.Class) + x.bandwidth() / 2)
    .attr("y", d =&gt; y(d["Average Age"]) - 8)
    .attr("text-anchor", "middle")
    .attr("font-size", "13px")
    .attr("fill", "#333")
    .text(d =&gt; d["Average Age"]);

  g.append("g")
    .attr("transform", `translate(0,${innerHeight})`)
    .call(d3.axisBottom(x))
    .call(a =&gt; a.select(".domain").remove());

  g.append("g")
    .call(d3.axisLeft(y).ticks(5))
    .call(a =&gt; a.select(".domain").remove());

  svg.append("text")
    .attr("transform", "rotate(-90)")
    .attr("x", -(height / 2))
    .attr("y", 16)
    .attr("text-anchor", "middle")
    .attr("font-size", "12px")
    .attr("fill", "#666")
    .text("Average Age");

  return svg.node();
}

